]

def parse_png_text(data):
    out=[]
    if not data.startswith(b'\x89PNG\r\n\x1a\n'):
        return out
    i=8
    while i+8<=len(data):
        length=struct.unpack('>I', data[i:i+4])[0]
        ctype=data[i+4:i+8]
        chunk=data[i+8:i+8+length]
        #crc=data[i+8+length:i+12+length]
        if ctype in (b'tEXt', b'iTXt', b'zTXt'):
            if ctype==b'tEXt':
                out.append(('tEXt', chunk))
            elif ctype==b'zTXt':
                try:
                    key, rest = chunk.split(b'\x00',1)
                    comp_meth=rest[0]
                    comp_data=rest[1:]
                    if comp_meth==0:
                        text=zlib.decompress(comp_data)
                        out.append(('zTXt', key+b'='+text))
                except Exception as e:
                    out.append(('zTXt_err', str(e)))
            elif ctype==b'iTXt':
                try:
                    parts=chunk.split(b'\x00',5)
                    if len(parts)>=6:
                        key=parts[0]
                        compressed_flag=parts[1]
                        comp_meth=parts[2]
                        lang=parts[3]
                        translated=parts[4]
                        text=parts[5]
                        if compressed_flag==b'\x01' and comp_meth==b'\x00':
                            text=zlib.decompress(text)
                        out.append(('iTXt', key+b'='+text))
                except Exception as e:
                    out.append(('iTXt_err', str(e)))
        i+=12+length
    return out

for p in paths:
