import re, requests, urllib.parse
base='http://localhost:5000'
visited=set()
queue=['/']
parents={}
status_map={}

def norm(u):
    if u.startswith('http'):
        if not u.startswith(base):
            return None
        return urllib.parse.urlparse(u).path
    return urllib.parse.urlparse(urllib.parse.urljoin(base,u)).path

while queue:
    p=queue.pop(0)
    if p in visited: continue
    visited.add(p)
    try:
        r=requests.get(base+p, timeout=8)
        status_map[p]=(r.status_code, r.headers.get('Content-Type',''))
    except Exception as e:
        status_map[p]=(None, str(e))
        continue
    ct=r.headers.get('Content-Type','')
    if 'text/html' in ct or 'text/css' in ct:
        text=r.text
        for m in re.finditer(r'(?:href|src)=["\']([^"\']+)["\']', text):
            u=norm(m.group(1))
            if u and u not in visited and u not in queue:
                parents[u]=p
                queue.append(u)
        if 'text/css' in ct:
            for m in re.finditer(r'url\(([^)]+)\)', text):
                u=m.group(1).strip('"\'')
                u=norm(u)
                if u and u not in visited and u not in queue:
                    parents[u]=p
                    queue.append(u)

print('Discovered paths:')
for p in sorted(status_map):
    print('%-40s -> %s %s (via %s)' % (p, status_map[p][0], status_map[p][1], parents.get(p,'')))

